#include <memory>
#include <iostream>

template <typename K, typename V>
class RedBlackTree {
    enum Color { RED, BLACK };

    struct Node {
        K key;
        V value;
        Color color = RED;
        Node *left = nullptr, *right = nullptr, *parent = nullptr;
        Node(K k, V v) : key(std::move(k)), value(std::move(v)) {}
    };

    Node* root = nullptr;

    void rotate_left(Node* x) {
        Node* y = x->right;
        x->right = y->left;
        if (y->left) y->left->parent = x;
        y->parent = x->parent;
        if (!x->parent) root = y;
        else if (x == x->parent->left) x->parent->left = y;
        else x->parent->right = y;
        y->left = x;
        x->parent = y;
    }

    void rotate_right(Node* x) {
        Node* y = x->left;
        x->left = y->right;
        if (y->right) y->right->parent = x;
        y->parent = x->parent;
        if (!x->parent) root = y;
        else if (x == x->parent->right) x->parent->right = y;
        else x->parent->left = y;
        y->right = x;
        x->parent = y;
    }

    void fix_insert(Node* z) {
        while (z->parent && z->parent->color == RED) {
            Node* gp = z->parent->parent;
            if (z->parent == gp->left) {
                Node* uncle = gp->right;
                if (uncle && uncle->color == RED) {
                    z->parent->color = BLACK;
                    uncle->color = BLACK;
                    gp->color = RED;
                    z = gp;
                } else {
                    if (z == z->parent->right) { z = z->parent; rotate_left(z); }
                    z->parent->color = BLACK;
                    gp->color = RED;
                    rotate_right(gp);
                }
            } else {
                // 镜像处理
                Node* uncle = gp->left;
                if (uncle && uncle->color == RED) {
                    z->parent->color = BLACK;
                    uncle->color = BLACK;
                    gp->color = RED;
                    z = gp;
                } else {
                    if (z == z->parent->left) { z = z->parent; rotate_right(z); }
                    z->parent->color = BLACK;
                    gp->color = RED;
                    rotate_left(gp);
                }
            }
        }
        root->color = BLACK;
    }

public:
    void insert(K key, V value) {
        Node* z = new Node(std::move(key), std::move(value));
        Node *y = nullptr, *x = root;
        while (x) {
            y = x;
            x = (z->key < x->key) ? x->left : x->right;
        }
        z->parent = y;
        if (!y) root = z;
        else if (z->key < y->key) y->left = z;
        else y->right = z;
        fix_insert(z);
    }
};
