# 通用 PowerShell 内存操作工具集
# 用途：调试器开发、运行时代码插桩、性能分析工具

Add-Type @'
using System;
using System.Runtime.InteropServices;

public static class MemUtil {
    [DllImport("kernel32.dll")]
    public static extern IntPtr LoadLibrary(string lpFileName);

    [DllImport("kernel32.dll", CharSet = CharSet.Ansi)]
    public static extern IntPtr GetProcAddress(IntPtr hModule, string procName);

    [DllImport("kernel32.dll")]
    public static extern bool VirtualProtect(
        IntPtr lpAddress, UIntPtr dwSize,
        uint flNewProtect, out uint lpflOldProtect);
}
'@

function Get-ExportAddress {
    param([string]$Module, [string]$Function)
    $h = [MemUtil]::LoadLibrary($Module)
    if ($h -eq [IntPtr]::Zero) { throw 'LoadLibrary failed' }
    $addr = [MemUtil]::GetProcAddress($h, $Function)
    if ($addr -eq [IntPtr]::Zero) { throw 'GetProcAddress failed' }
    return $addr
}

function Set-MemoryBytes {
    param([IntPtr]$Address, [byte[]]$Bytes)
    $size = [UIntPtr]::new($Bytes.Length)
    $oldProtect = 0
    # 切换为 PAGE_EXECUTE_READWRITE (0x40)
    [MemUtil]::VirtualProtect($Address, $size, 0x40, [ref]$oldProtect) | Out-Null
    [System.Runtime.InteropServices.Marshal]::Copy($Bytes, 0, $Address, $Bytes.Length)
    # 恢复原权限
    [MemUtil]::VirtualProtect($Address, $size, $oldProtect, [ref]$oldProtect) | Out-Null
    Write-Host "[+] Wrote $($Bytes.Length) bytes at $Address (original protect: 0x$($oldProtect.ToString('X')))"
}

function Get-MemoryBytes {
    param([IntPtr]$Address, [int]$Count)
    $buf = New-Object byte[] $Count
    [System.Runtime.InteropServices.Marshal]::Copy($Address, $buf, 0, $Count)
    return ($buf | ForEach-Object { $_.ToString('X2') }) -join ' '
}

# 使用示例：dump kernel32!CreateFileW 起始 16 字节
# $addr = Get-ExportAddress 'kernel32.dll' 'CreateFileW'
# Get-MemoryBytes -Address $addr -Count 16
```

实现要点：
- LoadLibrary 已加载的模块直接返回 handle，不会重复加载
- VirtualProtect 改为 PAGE_EXECUTE_READWRITE 后写入，再恢复原权限
- Marshal.Copy 双向用：byte[] → IntPtr 是写，IntPtr → byte[] 是读
- Get-MemoryBytes 可以用于 dump 函数序言，对比 patch 前后差异

